<h2 style="margin-bottom:20px">Modifier l'article</h2><form action="/admin/articles/<?=(int)$post['id']?>"method="post"style="background:#fff;padding:20px;border-radius:8px;box-shadow:0 2px 8px rgba(0,0,0,.1)"><label>Titre</label><br><input name="title"required style="width:100%;padding:10px;margin:8px 0 14px"value="<?=htmlspecialchars($post['title'])?>"><br><label>Contenu</label><br><textarea name="content"required rows="8"style="width:100%;padding:10px;margin:8px 0 14px"><?=htmlspecialchars($post['content'])?></textarea><br><label>Statut</label><br><select name="status"style="width:100%;padding:10px;margin:8px 0 14px"><option value="draft"<?=$post['status']==='draft'?'selected':''?>>Brouillon</option><option value="published"<?=$post['status']==='published'?'selected':''?>>Publié</option></select><br><button style="padding:10px 16px;background:#667eea;color:#fff;border:0;border-radius:5px"type="submit">Mettre à jour</button></form>